            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "code": "UNIT_PARAMETER_INCOMPLETE",
          "message": "Balance Heater is configured for outlet temperature control but outlet temperature target is missing.",
          "severity": "error",
          "target_type": "unit",
          "target_id": "heater-4",
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Cold Feed 补充流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-13"
          },
          "rationale": "诊断直接指出 feed-13 缺少流量规格；在当前证据下，添加流量占位是最小且可审查的局部补全，不扩展到其他未被直接确认的条件。",
          "patch": {
            "spec_placeholders": {
              "flow_rate": {
                "status": "required_missing",
                "description": "Provide stream flow rate specification for Cold Feed."
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Balance Heater 补充出口温度目标占位",
          "target": {
            "type": "unit",
            "id": "heater-4"
          },
          "rationale": "heater-4 已配置为 outlet_temperature 控制模式，但缺少对应目标值；补充目标参数占位与现有控制模式直接一致，且不涉及拓扑或执行式求解变更。",
          "patch": {
            "parameter_placeholders": {
              "outlet_temperature_target_c": {
                "status": "required_missing",
                "description": "Provide heater outlet temperature target for outlet_temperature control mode."
              }
